import os
from django.db import models
from django.contrib.auth.models import AbstractUser


class Role(models.Model):
    name = models.CharField('Название', max_length=100, unique=True)

    class Meta:
        verbose_name = 'Роль'
        verbose_name_plural = 'Роли'

    def __str__(self):
        return self.name


class User(AbstractUser):
    full_name = models.CharField('ФИО', max_length=255, blank=True)
    role = models.ForeignKey(
        Role,
        on_delete=models.SET_NULL,
        null=True,
        blank=True,
        verbose_name='Роль',
    )

    class Meta:
        verbose_name = 'Пользователь'
        verbose_name_plural = 'Пользователи'

    def __str__(self):
        return self.full_name or self.username

    @property
    def is_admin(self):
        return self.role and self.role.name.lower() == 'администратор'

    @property
    def is_manager(self):
        return self.role and self.role.name.lower() == 'менеджер'

    @property
    def is_client(self):
        return self.role and self.role.name.lower() == 'клиент'


class Category(models.Model):
    name = models.CharField('Название', max_length=255, unique=True)

    class Meta:
        verbose_name = 'Категория'
        verbose_name_plural = 'Категории'

    def __str__(self):
        return self.name


class Manufacturer(models.Model):
    name = models.CharField('Название', max_length=255, unique=True)

    class Meta:
        verbose_name = 'Производитель'
        verbose_name_plural = 'Производители'

    def __str__(self):
        return self.name


class Supplier(models.Model):
    name = models.CharField('Название', max_length=255, unique=True)

    class Meta:
        verbose_name = 'Поставщик'
        verbose_name_plural = 'Поставщики'

    def __str__(self):
        return self.name


class Product(models.Model):
    article = models.CharField('Артикул', max_length=100, unique=True)
    name = models.CharField('Наименование', max_length=255)
    unit = models.CharField('Единица измерения', max_length=50, default='шт.')
    price = models.DecimalField('Цена', max_digits=10, decimal_places=2)
    discount = models.DecimalField(
        'Скидка (%)', max_digits=5, decimal_places=2, default=0
    )
    quantity = models.PositiveIntegerField('Количество на складе', default=0)
    description = models.TextField('Описание', blank=True)
    photo = models.ImageField('Фото', upload_to='products/', blank=True, null=True)
    category = models.ForeignKey(
        Category, on_delete=models.PROTECT, verbose_name='Категория',
        null=True, blank=True,
    )
    manufacturer = models.ForeignKey(
        Manufacturer, on_delete=models.PROTECT, verbose_name='Производитель',
        null=True, blank=True,
    )
    supplier = models.ForeignKey(
        Supplier, on_delete=models.PROTECT, verbose_name='Поставщик',
        null=True, blank=True,
    )

    class Meta:
        verbose_name = 'Товар'
        verbose_name_plural = 'Товары'
        ordering = ['name']

    def __str__(self):
        return f'{self.article} — {self.name}'

    @property
    def discounted_price(self):
        if self.discount:
            return round(self.price * (1 - self.discount / 100), 2)
        return self.price

    def save(self, *args, **kwargs):
        if self.pk:
            try:
                old = Product.objects.get(pk=self.pk)
                if old.photo and old.photo != self.photo:
                    if os.path.isfile(old.photo.path):
                        os.remove(old.photo.path)
            except Product.DoesNotExist:
                pass
        super().save(*args, **kwargs)

    def delete(self, *args, **kwargs):
        if self.photo and os.path.isfile(self.photo.path):
            os.remove(self.photo.path)
        super().delete(*args, **kwargs)


class PickupPoint(models.Model):
    address = models.CharField('Адрес', max_length=500)

    class Meta:
        verbose_name = 'Пункт выдачи'
        verbose_name_plural = 'Пункты выдачи'

    def __str__(self):
        return self.address


class Order(models.Model):
    STATUS_CHOICES = [
        ('new', 'Новый'),
        ('completed', 'Завершён'),
    ]

    order_date = models.DateField('Дата заказа')
    delivery_date = models.DateField('Дата доставки')
    pickup_point = models.ForeignKey(
        PickupPoint, on_delete=models.PROTECT, verbose_name='Пункт выдачи',
    )
    client = models.ForeignKey(
        User, on_delete=models.PROTECT, verbose_name='Клиент',
        related_name='orders',
    )
    status = models.CharField(
        'Статус', max_length=20, choices=STATUS_CHOICES, default='new',
    )
    pickup_code = models.PositiveIntegerField('Код получения', blank=True, null=True)

    class Meta:
        verbose_name = 'Заказ'
        verbose_name_plural = 'Заказы'
        ordering = ['-order_date']

    def __str__(self):
        return f'Заказ #{self.pk} от {self.order_date}'


class OrderItem(models.Model):
    order = models.ForeignKey(
        Order, on_delete=models.CASCADE, verbose_name='Заказ',
        related_name='items',
    )
    product = models.ForeignKey(
        Product, on_delete=models.PROTECT, verbose_name='Товар',
    )
    quantity = models.PositiveIntegerField('Количество', default=1)

    class Meta:
        verbose_name = 'Позиция заказа'
        verbose_name_plural = 'Позиции заказа'

    def __str__(self):
        return f'{self.product.name} x{self.quantity}'
